Sure, let's move on to the "linked list" data structure. Unlike arrays, linked lists are not indexed, and each element is a separate object that holds a value and a reference to the next element in the sequence.

Here's an example of a singly linked list in JavaScript:

```javascript
class Node {
  constructor(value) {
    this.value = value;
    this.next = null;
  }
}

class LinkedList {
  constructor() {
    this.head = null;
  }

  append(value) {
    let newNode = new Node(value);
    if (!this.head) {
      this.head = newNode;
    } else {
      let current = this.head;
      while (current.next) {
        current = current.next;
      }
      current.next = newNode;
    }
  }

  print() {
    let current = this.head;
    while (current) {
      console.log(current.value);
      current = current.next;
    }
  }
}

let list = new LinkedList();
list.append(1);
list.append(2);
list.append(3);
list.print(); // Outputs: 1, 2, 3
